--[[ Moon Pixel — packed payload (XOR+Base64). Original logic unchanged; requires loadstring. ]]
local _K=[==[RC2MPx!9#kL2$nQ8@vZ4%wR7*hJ5tN6^bM3]==]
local _B={[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==],[==[]==]}
local function _b64(d)
	local B='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
	local L={}
	for i=1,64 do L[string.byte(B,i)]=i-1 end
	d=d:gsub('%s+','')
	local o,n={},#d
	local i=1
	while i<=n do
		local a,b,c,e=d:byte(i,i+3)
		i=i+4
		local A,B,C,E=L[a]or 0,L[b]or 0,L[c]or 0,L[e]or 0
		local v=A*262144+B*4096+C*64+E
		local x1=math.floor(v/65536)%256
		local x2=math.floor(v/256)%256
		local x3=v%256
		if e==61 then
			if c==61 then o[#o+1]=string.char(x1)
			else o[#o+1]=string.char(x1,x2) end
		else o[#o+1]=string.char(x1,x2,x3) end
	end
	return table.concat(o)
end
local function _xor(s)
	local o,lk={},#_K
	for i=1,#s do
		local a=string.byte(s,i)
		local k=string.byte(_K,(i-1)%lk+1)
		o[i]=string.char(bit32.bxor(a,k))
	end
	return table.concat(o)
end
local _src=_xor(_b64(table.concat(_B)))
local _fn,err=loadstring(_src,'@MoonPixel')
if not _fn then error(tostring(err),2) end
return _fn()
